# Non-circular verification of P3 tests WITHOUT editing the repo.
# Replicate the fake_pg harness, then directly inspect what the assertions measure.
import sys, types
from assay_engine.persistence import checkpoint as cp

state = {"setup_on": [], "lock_on": [], "pools": [], "atexit_registered": 0}
class FakeConn:
    def execute(self, sql, params=None):
        if "pg_advisory_lock" in sql: state["lock_on"].append(id(self))
class FakePool:
    check_connection = staticmethod(lambda *a,**k: None)
    def __init__(self, conn_str, **kw):
        self.conn_str=conn_str; self._conn=FakeConn(); state["pools"].append(self)
    def connection(self):
        conn=self._conn
        class C:
            def __enter__(s): return conn
            def __exit__(s,*a): return False
        return C()
    def close(self): pass
class FakeSaver:
    def __init__(self, arg): self.arg=arg
    def setup(self): state["setup_on"].append(id(self.arg))
def mod(n,**a):
    m=types.ModuleType(n)
    for k,v in a.items(): setattr(m,k,v)
    sys.modules[n]=m
for n in ["langgraph","langgraph.checkpoint","psycopg"]: mod(n)
mod("langgraph.checkpoint.postgres", PostgresSaver=FakeSaver)
mod("langgraph.checkpoint.memory", MemorySaver=type("M",(),{}))
mod("psycopg.rows", dict_row=object())
mod("psycopg_pool", ConnectionPool=FakePool)
cp._INITIALIZED_CONN_STRS=set(); cp._OPEN_POOLS=[]; cp._atexit_registered=False
cp.atexit=types.SimpleNamespace(register=lambda fn: state.__setitem__("atexit_registered", state["atexit_registered"]+1))
import os; os.environ["ASSAY_POSTGRES_URL"]="postgresql://localhost:5432/assay"

cp.get_checkpointer(); cp.get_checkpointer()
print("setup_on count:", len(state["setup_on"]), "(test asserts ==1)")
print("lock_on == setup_on:", state["lock_on"]==state["setup_on"], "ids:", state["lock_on"], state["setup_on"])
print("pools:", len(state["pools"]), "atexit_registered:", state["atexit_registered"])
# Non-circular proof: setup_on records id(self.arg) where arg is the CONN during setup,
# and the pool-backed saver returned later is NOT recorded. lock_on records id(conn).
# So lock_on==setup_on proves DDL ran on the locked connection (not a pool conn).
# If the guard were removed, setup_on would be len 2 -> test fails. Genuine.
